scwin.f_gridToExcel = async function (argGrid, argTitle) {
  // 검색조건
  var totCnt = ds_eqMan.getRowCount();
  var colCnt = 0;
  if (totCnt != "0") {
    var cfrm = await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
      var checkSub = "false";
      if (chb_dailygb.getValue() == 1) {
        checkSub = "true";
        colCnt = 15;
      } else {
        colCnt = 10;
      }
      const options = {
        fileName: "급여집계(장비).xlsx",
        //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName: "급여집계(장비)",
        startRowIndex: 2,
        startColumnIndex: 0,
        useSubTotal: checkSub
      };

      // 타이틀
      const infoArr = [{
        rowIndex: 0,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colCnt,
        text: "급여집계(장비)",
        textAlign: "center",
        drawBorder: false,
        fontSize: "18px"
      }];
      $c.data.downloadGridViewExcel($p, gr_eqMan, options, infoArr);
    }
  } else {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
  }
};
