scwin.udc_comCodeStaff_onclickEvent = function (e) {
  scwin.f_openCommonPopUp(1, ed_staffNo.getValue(), ed_staffNm.getValue());
};
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
  let arrParam = new Array();
  arrParam[0] = pCode; //사번
  arrParam[1] = pName; //사원명
  arrParam[2] = acb_lobranCd.getValue(); //점소코드
  arrParam[3] = acb_lobranCd.getText(true); //점소명
  arrParam[4] = ''; //작업장코드
  arrParam[5] = ''; //직종  (정규직)
  arrParam[6] = ''; //상세직종코드 
  arrParam[7] = ''; //직급
  arrParam[8] = ''; //작업일
  arrParam[9] = ''; //배치가능여부
  arrParam[10] = 'T'; //WINDOW CLOSE 여부
  arrParam[11] = "1"; //상세직종Flag
  arrParam[13] = ed_wrkStDt.getValue();
  arrParam[14] = ed_wrkEndDt.getValue();

  // 팝업 옵션 설정
  let options = {
    id: "taxPop",
    type: "",
    popupName: "인력검색",
    width: 800,
    height: 500
  };
  ed_staffNo.setValue("");
  ed_staffNm.setValue("");
  //상세화면 호출
  rtnList = await $c.win.openPopup($p, "/ui/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.xml", options, arrParam);

  //결과값 (udc 정리후 retest)
  if (rtnList.length > 0) {
    ed_staffNo.setValue(rtnList[2]);
    ed_staffNm.setValue(rtnList[3]);
  } else {
    ed_staffNo.setValue("");
    ed_staffNm.setValue("");
  }
};
scwin.udc_comCodeStaff_onblurCodeEvent = function (e) {
  if (ed_staffNo.getValue() === "") {
    ed_staffNm.setValue("");
  } else {
    scwin.f_chkOpenCommonPopUp(ed_staffNo, ed_staffNm, 1, true);
  }
};
scwin.udc_comCodeStaff_onviewchangeNameEvent = function (info) {
  if (ed_staffNm.getValue() === "") {
    ed_staffNo.setValue("");
  } else {
    scwin.f_chkOpenCommonPopUp(ed_staffNm, ed_staffNo, 1, false);
  }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!(await $c.gus.cfCanOpenPopup($p, inObj, pairObj))) return;

  // 짝이 되는 오브젝트의 값 제거
  await $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  var pVal = await $c.gus.cfGetValue($p, inObj);

  // inObj가 코드 필드일 경우 팝업
  if (isCode == null || isCode == true) scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
  // inObj가 코드명 필드일 경우 팝업
  else scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};
scwin.tac_tabControl1_ontabclick = function (tabId, index) {
  if (ds_eqMan.getRowCount() != 0 || ds_stvMan.getRowCount()) {
    if (chb_dailygb.getValue() == 0) {
      gr_eqMan.setColumnVisible("workDt", false);
      gr_stvMan.setColumnVisible("workDt", false);
      gr_eqMan.setColumnVisible("fromStHh", false);
      gr_stvMan.setColumnVisible("fromStHh", false);
      gr_eqMan.setColumnVisible("fromEndHh", false);
      gr_stvMan.setColumnVisible("fromEndHh", false);
      gr_eqMan.setColumnVisible("toStHh", false);
      gr_stvMan.setColumnVisible("toStHh", false);
      gr_eqMan.setColumnVisible("toEndHh", false);
      gr_stvMan.setColumnVisible("toEndHh", false);
      gr_eqMan.setSubtotalVisible(false);
      gr_stvMan.setSubtotalVisible(false);

      // ds_eqMan.SubsumExpr = "";
      // ds_stvMan.SubsumExpr = "";
    } else {
      gr_eqMan.setColumnVisible("workDt", true);
      gr_stvMan.setColumnVisible("workDt", true);
      gr_eqMan.setColumnVisible("fromStHh", true);
      gr_stvMan.setColumnVisible("fromStHh", true);
      gr_eqMan.setColumnVisible("fromEndHh", true);
      gr_stvMan.setColumnVisible("fromEndHh", true);
      gr_eqMan.setColumnVisible("toStHh", true);
      gr_stvMan.setColumnVisible("toStHh", true);
      gr_eqMan.setColumnVisible("toEndHh", true);
      gr_stvMan.setColumnVisible("toEndHh", true);
      gr_eqMan.setSubtotalVisible(true);
      gr_stvMan.setSubtotalVisible(true);
      // ds_eqMan.SubsumExpr = '1:staffNm';
      // ds_stvMan.SubsumExpr = '1:staffNm';
    }
  }
  totalRows3.setValue(ds_stvMan.getRowCount());
};

//////////////////////////////////////// S U B M I S S I O N    E V E N T //////////////////////////////////

scwin.sbm_retrieve_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) {
    //$c.gus.cfShowError(sbm_Retrieve);
    return;
  }
  ;
  if (chb_dailygb.getValue() == 0) {
    gr_eqMan.setSubtotalVisible(false);
    gr_stvMan.setSubtotalVisible(false);
  } else {
    gr_eqMan.setSubtotalVisible(true);
    gr_stvMan.setSubtotalVisible(true);
    scwin.f_detail(0);
  }
  ;
  totalRows1.setValue(ds_eqMan.getRowCount());
  totalRows3.setValue(ds_stvMan.getRowCount());
  if (ds_eqMan.getRowCount() > 0) {
    if (chb_dailygb.getValue() == "1") {
      scwin.f_detail(0);
    }
    ;
  } else {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_003);
  }
  ;
  if (ds_stvMan.getRowCount() > 0) {
    if (chb_dailygb.getValue() == "1") {
      scwin.f_detail2(0);
    }
  } else {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_003);
  }
  ;
  if (ds_payDetail.getRowCount() == 0) {
    totalRows2.setValue(0);
  }
  // totalRows3.setValue(ds_stvMan.getRowCount());
};
scwin.sbm_retrieveDetail_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) {
    //$c.gus.cfShowError(sbm_Retrieve);
    return;
  }
  totalRows2.setValue(ds_payDetail.getRowCount());
};
scwin.changeVal = function (e) {
  var vals = e;
  if (e == "0" || e == "") {
    vals = "";
  } else {
    vals = WebSquare.text.formatFloat(vals, "#,###.0");
  }
  return vals;
};
scwin.gr_eqMan_oncellclick = function (rowIndex, columnIndex, columnId) {
  if (chb_dailygb.getValue() == 1) {
    scwin.f_detail(rowIndex);
  }
};
scwin.gr_stvMan_oncellclick = function (rowIndex, columnIndex, columnId) {
  scwin.f_detail2(rowIndex);
};
scwin.gr_stvMan_onsubtotalclick = function (info) {
  ds_payDetail.removeAll();
};
scwin.gr_eqMan_onsubtotalclick = function (info) {
  ds_payDetail.removeAll();
};
